  ('dietitian-moex-03463', 'dietitian', 'dietitian-moex-101-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '行政院衛生署所公告之現行「國人膳食營養素參考攝取量」中，「適度」的活動強度為使個案在每單位 時間內熱量需求量增加多少百分比？', '["30", "50", "70", "80"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "ebef43dc8854", "answer_pdf_sha1": "0e9e5a200d18", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03464', 'dietitian', 'dietitian-moex-101-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '過量攝取維生素D會造成高血鈣症、軟組織轉移性鈣化以及憂鬱、厭食、噁心、嘔吐等症狀。我國國人 膳食營養素參考攝取量中建議18歲以上成人之維生素D上限攝取量為：', '["25μg", "50μg", "400 IU", "1000 IU"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "ebef43dc8854", "answer_pdf_sha1": "0e9e5a200d18", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03465', 'dietitian', 'dietitian-moex-101-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '王先生、47歲、BMI為25、抽菸、有高血壓的症狀。根據行政院衛生署公布成人肥胖處理流程，下列何 者最為適當？', '["執行飲食控制，並針對高血壓進行控制", "執行飲食控制，並給予運動指導", "飲食控制與運動指導，並修正生活習慣", "飲食控制、運動指導、修正生活習慣，戒菸，並針對高血壓進行控制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "ebef43dc8854", "answer_pdf_sha1": "0e9e5a200d18", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03466', 'dietitian', 'dietitian-moex-101-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關「校園飲品及點心販售範圍」規範，下列敘述何者錯誤？', '["適用於國小、國中，高中職不在規範中", "飲品及點心食品一份供應量之熱量應在250大卡以下", "飲品只有純果（蔬菜）汁、鮮乳、優酪乳、包裝飲用水", "麵包中油及糖所提供熱量之總和不得超過總熱量之40 %"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "ebef43dc8854", "answer_pdf_sha1": "0e9e5a200d18", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03467', 'dietitian', 'dietitian-moex-101-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '林小姐於某校營養系畢業後即進入某瘦身美容中心擔任個別會員營養需求評估、飲食設計及營養諮詢的 工作，已有6年的時間，但一直未取得營養師資格。依據營養師法，必須接受下列何種處罰？', '["沒有相關罰則", "林小姐本人及其雇主各處新台幣五萬元以上二十五萬元以下罰鍰", "林小姐處五萬元以上二十五萬元以下罰鍰，雇主處二十萬元以上五十萬元以下罰鍰", "林小姐處五萬元以上二十五萬元以下罰鍰，雇主勒令停止營業"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "ebef43dc8854", "answer_pdf_sha1": "0e9e5a200d18", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03468', 'dietitian', 'dietitian-moex-101-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '國民營養健康狀況變遷調查中，用以評估維生素B狀態的方法為何？ 1B', '["紅血球丙胺酸轉胺酶活性係數（erythrocyte alanine transaminase activity coefficient）", "紅血球轉酮酶活性係數（erythrocyte transketolase activity coefficient）", "紅血球麩胱甘肽還原酶活性係數（erythrocyte glutathione reductase activity coefficient）", "甲基丙二酸輔酶A（methyl-malonyl coenzyme A）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "ebef43dc8854", "answer_pdf_sha1": "0e9e5a200d18", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03469', 'dietitian', 'dietitian-moex-101-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '缺乏下列何種營養素最可能導致癩皮性皮膚炎（pellagra dermatitis）的產生？', '["Vit C", "必需脂肪酸", "菸鹼酸", "鋅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "ebef43dc8854", "answer_pdf_sha1": "0e9e5a200d18", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03470', 'dietitian', 'dietitian-moex-101-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '美國推行之DASH飲食與下列何種疾病有關？', '["高血壓", "糖尿病", "肝硬化", "癌症"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "ebef43dc8854", "answer_pdf_sha1": "0e9e5a200d18", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03471', 'dietitian', 'dietitian-moex-101-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在人體處於穩定狀況下，那些指標可用來評估身體肌肉量（muscle mass）？①尿中鉀離子量  ②24小時', '["血清白蛋白濃度（albumin）", "三甲基組織胺（3-methylhisidine）", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "ebef43dc8854", "answer_pdf_sha1": "0e9e5a200d18", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
